import { useState, useEffect } from "react";
import Link from "next/link";
import { ArtifactCard } from "@/components/ArtifactCard";

interface Artifact {
  id: string;
  title: string;
  description: string | null;
  type: string;
  tags: string[];
  authorEmail: string;
  createdAt: string;
  mimeType: string;
}

export default function HomePage() {
  const [artifacts, setArtifacts] = useState<Artifact[]>([]);
  const [search, setSearch] = useState("");
  const [selectedTag, setSelectedTag] = useState<string | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchArtifacts();
  }, [search, selectedTag]);

  async function fetchArtifacts() {
    setLoading(true);
    const params = new URLSearchParams();
    if (search) params.set("search", search);
    if (selectedTag) params.set("tag", selectedTag);

    const res = await fetch(`/api/artifacts?${params}`);
    const data = await res.json();
    setArtifacts(data.artifacts || []);
    setLoading(false);
  }

  // Collect all unique tags
  const allTags = Array.from(new Set(artifacts.flatMap((a) => a.tags))).sort();

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Header */}
      <header className="bg-white border-b border-gray-200">
        <div className="max-w-6xl mx-auto px-6 py-4 flex items-center justify-between">
          <div>
            <h1 className="text-xl font-bold text-gray-900">Artifact Hub</h1>
            <p className="text-sm text-gray-500">
              Browse and share AI-generated content
            </p>
          </div>
          <Link
            href="/artifacts/new"
            className="px-4 py-2 bg-blue-600 text-white text-sm font-medium rounded-lg hover:bg-blue-700"
          >
            Publish
          </Link>
        </div>
      </header>

      {/* Search and filters */}
      <div className="max-w-6xl mx-auto px-6 py-6">
        <div className="flex gap-3 mb-4">
          <input
            type="text"
            placeholder="Search artifacts..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="flex-1 px-4 py-2.5 bg-white border border-gray-200 rounded-lg text-sm focus:outline-none focus:border-blue-400"
          />
        </div>

        {/* Tag filters */}
        {allTags.length > 0 && (
          <div className="flex flex-wrap gap-2 mb-6">
            <button
              onClick={() => setSelectedTag(null)}
              className={`text-xs px-3 py-1 rounded-full ${
                !selectedTag
                  ? "bg-blue-600 text-white"
                  : "bg-gray-100 text-gray-600 hover:bg-gray-200"
              }`}
            >
              All
            </button>
            {allTags.map((tag) => (
              <button
                key={tag}
                onClick={() => setSelectedTag(tag === selectedTag ? null : tag)}
                className={`text-xs px-3 py-1 rounded-full ${
                  selectedTag === tag
                    ? "bg-blue-600 text-white"
                    : "bg-gray-100 text-gray-600 hover:bg-gray-200"
                }`}
              >
                {tag}
              </button>
            ))}
          </div>
        )}

        {/* Gallery grid */}
        {loading ? (
          <div className="text-center py-12 text-gray-400">Loading...</div>
        ) : artifacts.length === 0 ? (
          <div className="text-center py-16">
            <p className="text-gray-500 mb-2">No artifacts yet</p>
            <Link
              href="/artifacts/new"
              className="text-blue-600 text-sm hover:underline"
            >
              Publish your first artifact
            </Link>
          </div>
        ) : (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-5">
            {artifacts.map((artifact) => (
              <ArtifactCard
                key={artifact.id}
                id={artifact.id}
                title={artifact.title}
                description={artifact.description}
                type={artifact.type}
                tags={artifact.tags}
                authorEmail={artifact.authorEmail}
                createdAt={artifact.createdAt}
                mimeType={artifact.mimeType}
              />
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

"use client";

import { useState, useEffect, use } from "react";
import Link from "next/link";
import { ArtifactViewer } from "@/components/ArtifactViewer";
import { FeedbackPanel } from "@/components/FeedbackPanel";
import { ShareDialog } from "@/components/ShareDialog";

interface Artifact {
  id: string;
  title: string;
  description: string | null;
  type: string;
  tags: string[];
  authorEmail: string;
  createdAt: string;
  fileName: string;
  fileSize: number;
  mimeType: string;
}

export default function ArtifactDetailPage({
  params,
}: {
  params: Promise<{ id: string }>;
}) {
  const { id } = use(params);
  const [artifact, setArtifact] = useState<Artifact | null>(null);
  const [loading, setLoading] = useState(true);
  const [showShare, setShowShare] = useState(false);

  useEffect(() => {
    fetch(`/api/artifacts/${id}`)
      .then((res) => res.json())
      .then((data) => {
        setArtifact(data.artifact || null);
        setLoading(false);
      });
  }, [id]);

  if (loading) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center text-gray-400">
        Loading...
      </div>
    );
  }

  if (!artifact) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <div className="text-center">
          <p className="text-gray-500 mb-2">Artifact not found</p>
          <Link href="/" className="text-blue-600 text-sm hover:underline">
            Back to gallery
          </Link>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Header */}
      <header className="bg-white border-b border-gray-200">
        <div className="max-w-5xl mx-auto px-6 py-4">
          <Link
            href="/"
            className="text-sm text-gray-500 hover:text-gray-700 mb-2 inline-block"
          >
            &larr; Back to gallery
          </Link>
          <div className="flex items-start justify-between">
            <div>
              <h1 className="text-2xl font-bold text-gray-900">
                {artifact.title}
              </h1>
              {artifact.description && (
                <p className="text-gray-500 mt-1">{artifact.description}</p>
              )}
              <div className="flex items-center gap-3 mt-2 text-sm text-gray-400">
                <span>{artifact.authorEmail}</span>
                <span>
                  {new Date(artifact.createdAt).toLocaleDateString()}
                </span>
                <span>{(artifact.fileSize / 1024).toFixed(1)} KB</span>
              </div>
            </div>
            <div className="flex gap-2">
              <button
                onClick={() => setShowShare(true)}
                className="px-4 py-2 border border-gray-200 text-sm rounded-lg hover:bg-gray-50"
              >
                Share
              </button>
              <a
                href={`/api/artifacts/${artifact.id}/file`}
                download={artifact.fileName}
                className="px-4 py-2 bg-blue-600 text-white text-sm rounded-lg hover:bg-blue-700"
              >
                Download
              </a>
            </div>
          </div>

          {/* Tags */}
          {artifact.tags.length > 0 && (
            <div className="flex flex-wrap gap-1.5 mt-3">
              {artifact.tags.map((tag) => (
                <span
                  key={tag}
                  className="text-xs px-2 py-0.5 bg-blue-50 text-blue-600 rounded-full"
                >
                  {tag}
                </span>
              ))}
            </div>
          )}
        </div>
      </header>

      {/* Content */}
      <div className="max-w-5xl mx-auto px-6 py-8 space-y-8">
        <ArtifactViewer
          artifactId={artifact.id}
          type={artifact.type}
          mimeType={artifact.mimeType}
          title={artifact.title}
        />

        <FeedbackPanel artifactId={artifact.id} />
      </div>

      {/* Share dialog */}
      {showShare && (
        <ShareDialog
          artifactId={artifact.id}
          onClose={() => setShowShare(false)}
        />
      )}
    </div>
  );
}

